600:     public CoordinatorResult<OffsetCommitResponseData, CoordinatorRecord> commitOffset(
601:         AuthorizableRequestContext context,
602:         OffsetCommitRequestData request
603:     ) throws ApiException {
604:         Group group = validateOffsetCommit(context, request);
605: 
606:         // In the old consumer group protocol, the offset commits maintain the session if
607:         // the group is in Stable or PreparingRebalance state.
608:         if (group.type() == Group.GroupType.CLASSIC) {
609:             ClassicGroup classicGroup = (ClassicGroup) group;
610:             if (classicGroup.isInState(ClassicGroupState.STABLE) || classicGroup.isInState(ClassicGroupState.PREPARING_REBALANCE)) {
611:                 groupMetadataManager.rescheduleClassicGroupMemberHeartbeat(
612:                     classicGroup,
613:                     classicGroup.member(request.memberId())
614:                 );
615:             }
616:         }
617: 
618:         final OffsetCommitResponseData response = new OffsetCommitResponseData();
619:         final List<CoordinatorRecord> records = new ArrayList<>();
620:         final long currentTimeMs = time.milliseconds();
621:         final OptionalLong expireTimestampMs = expireTimestampMs(request.retentionTimeMs(), currentTimeMs);
622: 
623:         request.topics().forEach(topic -> {
624:             final OffsetCommitResponseTopic topicResponse = new OffsetCommitResponseTopic()
625:                 .setTopicId(topic.topicId())
626:                 .setName(topic.name());
627:             response.topics().add(topicResponse);
628: 
629:             topic.partitions().forEach(partition -> {
630:                 if (isMetadataInvalid(partition.committedMetadata())) {
631:                     topicResponse.partitions().add(new OffsetCommitResponsePartition()
632:                         .setPartitionIndex(partition.partitionIndex())
633:                         .setErrorCode(Errors.OFFSET_METADATA_TOO_LARGE.code()));
634:                 } else {
635:                     log.debug("[GroupId {}] Committing offsets {} for partition {}-{}-{} from member {} with leader epoch {}.",
636:                         request.groupId(), partition.committedOffset(), topic.topicId(), topic.name(), partition.partitionIndex(),
637:                         request.memberId(), partition.committedLeaderEpoch());
638: 
639:                     topicResponse.partitions().add(new OffsetCommitResponsePartition()
640:                         .setPartitionIndex(partition.partitionIndex())
641:                         .setErrorCode(Errors.NONE.code()));
642: 
643:                     final OffsetAndMetadata offsetAndMetadata = OffsetAndMetadata.fromRequest(
644:                         topic.topicId(),
645:                         partition,
646:                         currentTimeMs,
647:                         expireTimestampMs
648:                     );
649: 
650:                     records.add(GroupCoordinatorRecordHelpers.newOffsetCommitRecord(
651:                         request.groupId(),
652:                         topic.name(),
653:                         partition.partitionIndex(),
654:                         offsetAndMetadata
655:                     ));
656:                 }
657:             });
658:         });
659: 
660:         if (!records.isEmpty()) {
661:             metrics.record(GroupCoordinatorMetrics.OFFSET_COMMITS_SENSOR_NAME, records.size());
662:         }
663: 
664:         return new CoordinatorResult<>(records, response);
665:     }
